    {\"step\": \"reporting\", \"status\": \"pending\"},
    {\"step\": \"validation\", \"status\": \"pending\"},
    {\"step\": \"submission\", \"status\": \"pending\"}
  ],
  \"complexity\": {
    \"score\": 1,
    \"reasons\": [
      \"Single rule (Article 10)\",
      \"Two directly related records\",
      \"Simple comparison of invoice numbers\",
      \"No aggregation, grouping, or batch filtering needed\",
      \"No policy version ambiguity\"
    ]
  },
  \"subagent_plan\": {
    \"requested\": false,
    \"reason\": \"Complexity 1; compact mode in main context is sufficient\"
  },
  \"stopping_conditions\": [
    \"Both invoice numbers confirmed different → no duplicate\",
    \"If same invoice found → duplicate anomaly\"
  ],
  \"unresolved_items\": []
}
